mapper.delete:
		/*
             SQL ID : OnlnPltfrmUserDAO.onlnPltfrmUserBulkDelete
             설  명  : 온라인플랫폼사용자일괄삭제
         */
        DELETE FROM TB_LMS_ONLN_PLTFRM_USER
         WHERE ONLN_PLTFRM_AUTHRT_ID = #{onlnPltfrmAuthrtId}
           AND PLTFRM_USER_EML NOT IN

           		#{email}

mapper.insert:
		/*
             SQL ID : OnlnPltfrmUserDAO.onlnPltfrmUserBulkRegist
             설  명 : 온라인플랫폼사용자일괄등록
         */
         INSERT ALL

			INTO TB_LMS_ONLN_PLTFRM_USER (
	         	  ONLN_PLTFRM_USER_ID
				, ONLN_PLTFRM_AUTHRT_ID
				, PLTFRM_USER_ID
				, PLTFRM_USER_EML
				, PLTFRM_USER_TYCD
				, PLTFRM_USER_STSCD
				, RGTR_ID
				, REG_DTTM
	         ) VALUES (
	         	  #{item.onlnPltfrmUserId}
				, #{item.onlnPltfrmAuthrtId}
				, #{item.pltfrmUserId}
				, #{item.pltfrmUserEml}
				, #{item.pltfrmUserTycd}
				, #{item.pltfrmUserStscd}
				, #{item.rgtrId}
				, FN_DTTM()
	         )

		SELECT * FROM DUAL

mapper.select:
/* SQL ID : OnlnPltfrmUserDAO.pendingOnlnPltfrmUserCntSelect 설 명 : 대기중온라인플랫폼사용자수조회 */ SELECT COUNT(*) AS CNT FROM (
SELECT COUNT(USR.ONLN_PLTFRM_USER_ID) AS AVAILABLE_CNT FROM TB_LMS_ONLN_PLTFRM_STNG STNG JOIN TB_LMS_ONLN_PLTFRM_AUTHRT AUTHRT ON STNG.ONLN_PLTFRM_STNG_ID = AUTHRT.ONLN_PLTFRM_STNG_ID JOIN TB_LMS_ONLN_PLTFRM_USER USR ON AUTHRT.ONLN_PLTFRM_AUTHRT_ID = USR.ONLN_PLTFRM_AUTHRT_ID AND USR.PLTFRM_USER_STSCD = 'active' AND USR.ONLN_PLTFRM_USER_ID NOT IN ( SELECT ONLN_PLTFRM_USER_ID FROM TB_LMS_ONLN_MEETNGRM WHERE MEETNGRM_SDTTM BETWEEN #{item.sdttm} AND #{item.edttm} OR MEETNGRM_EDTTM BETWEEN #{item.sdttm} AND #{item.edttm} GROUP BY ONLN_PLTFRM_USER_ID HAVING COUNT(*) >= 2 ) WHERE STNG.PLTFRM_GBNCD = #{item.gbn} AND STNG.ORG_ID = #{item.orgId}
) T WHERE T.AVAILABLE_CNT = 0
